async function run(params, api) {
  var repo = params.repo;
  api.log('Fetching repo info: ' + repo);
  var repoRaw = await api.httpGet('https://api.github.com/repos/' + repo);
  var info = JSON.parse(repoRaw);
  var result = {
    full_name: info.full_name,
    description: info.description,
    language: info.language,
    stars: info.stargazers_count,
    forks: info.forks_count,
    open_issues: info.open_issues_count,
    default_branch: info.default_branch,
    created_at: info.created_at,
    updated_at: info.updated_at,
    pushed_at: info.pushed_at,
    topics: info.topics,
    license: info.license ? info.license.spdx_id : null,
    url: info.html_url
  };
  if (params.include_releases !== false) {
    try {
      var relRaw = await api.httpGet('https://api.github.com/repos/' + repo + '/releases/latest');
      var rel = JSON.parse(relRaw);
      result.latest_release = { tag: rel.tag_name, name: rel.name, published_at: rel.published_at, url: rel.html_url };
    } catch (e) {
      result.latest_release = null;
    }
  }
  return JSON.stringify(result, null, 2);
}
